def get_configs(interpretation):
    configs = []
    if interpretation == 1:  # At least one box >= 2 (trivially true with 30 coins)
        for a in range(31):
            for b in range(31):
                c = 30 - a - b
                if c >= 0 and (abs(a - b) == 6 or abs(a - c) == 6 or abs(b - c) == 6):
                    configs.append((a, b, c))
    elif interpretation == 2:  # Each box >= 2
        for a in range(2, 29):
            for b in range(2, 29):
                c = 30 - a - b
                if c >= 2 and (abs(a - b) == 6 or abs(a - c) == 6 or abs(b - c) == 6):
                    configs.append((a, b, c))
    elif interpretation == 3:  # At least one box has exactly 2
        for a in range(31):
            for b in range(31):
                c = 30 - a - b
                if c >= 0 and min(a, b, c) == 2 and (abs(a - b) == 6 or abs(a - c) == 6 or abs(b - c) == 6):
                    configs.append((a, b, c))
    return configs

def optimal_strategy(configs):
    best = (0, 0, 0)
    best_min = 0
    for g1 in range(0, 31):
        for g2 in range(0, 31):
            for g3 in range(0, 31):
                min_pay = float('inf')
                for config in configs:
                    payoff = sum(min(g, c) if g <= c else 0 for g, c in zip((g1, g2, g3), config))
                    min_pay = min(min_pay, payoff)
                if min_pay > best_min:
                    best_min = min_pay
                    best = (g1, g2, g3)
    return best, best_min

for interp in [1, 2, 3]:
    configs = get_configs(interp)
    strategy, min_guarantee = optimal_strategy(configs)
    print(f"Interpretation {interp}: {len(configs)} configs, optimal strategy {strategy}, minimum guarantee = {min_guarantee}")
