# Let me do a more thorough search for the optimal strategy
# With each box having at least 2 coins

configs = []
for a in range(2, 29):
    for b in range(2, 29):
        c = 30 - a - b
        if c >= 2:
            if abs(a - b) == 6 or abs(a - c) == 6 or abs(b - c) == 6:
                configs.append((a, b, c))

print(f"Total configs: {len(configs)}")

# Find optimal strategy by checking ALL possible guess combinations
# Guesses can range from 0 to 30 (max coins)
best = (0, 0, 0)
best_min = 0

for g1 in range(0, 31):
    for g2 in range(0, 31):
        for g3 in range(0, 31):
            # Calculate minimum payoff for this guess strategy
            min_pay = float('inf')
            for config in configs:
                payoff = sum(min(g, c) if g <= c else 0 for g, c in zip((g1, g2, g3), config))
                min_pay = min(min_pay, payoff)
            if min_pay > best_min:
                best_min = min_pay
                best = (g1, g2, g3)

print(f"Best strategy: {best}")
print(f"Minimum guarantee: {best_min}")

# Show what happens with the optimal strategy for each config
print("\nDetailed results with optimal strategy:")
for config in sorted(configs):
    payoff = sum(min(g, c) if g <= c else 0 for g, c in zip(best, config))
    matches = []
    for g, c in zip(best, config):
        if g <= c:
            matches.append(f"{g}<={c}")
        else:
            matches.append(f"{g}>{c}")
    print(f"  {config}: payoff = {payoff} ({', '.join(matches)})")
